# Write-CanonFiles2.ps1 ? Creates ADR-048, D1.1 discovery scripts, and architecture diagrams
# Run from: C:\Users\whale\git\uiao\tools\
# Usage:    powershell -ExecutionPolicy Bypass -File .\Write-CanonFiles2.ps1

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

param(
    [string]$RepoRoot = "C:\Users\whale\git\uiao"
)

if (-not (Test-Path $RepoRoot)) {
    Write-Error "Repo root not found: $RepoRoot"
    return
}

function Write-B64File {
    param(
        [Parameter(Mandatory)][string]$Base64,
        [Parameter(Mandatory)][string]$TargetPath,
        [string]$Label = $null
    )

    $dir = Split-Path $TargetPath -Parent
    if (-not (Test-Path $dir)) {
        New-Item -Path $dir -ItemType Directory -Force | Out-Null
    }

    if ($Label) {
        Write-Host "Writing $Label..."
    } else {
        Write-Host "Writing $TargetPath..."
    }

    $bytes = [Convert]::FromBase64String($Base64)
    [System.IO.File]::WriteAllBytes($TargetPath, $bytes)

    Write-Host "  OK  $TargetPath" -ForegroundColor Green
}

