# --- Architecture diagram 1 ? OrgPath logical model (PlantUML) ---
$orgPathDiagram1 = @"
@startuml
title OrgPath logical model (UIAO)

skinparam backgroundColor #FFFFFF
skinparam classAttributeIconSize 0
skinparam defaultTextAlignment left

package ""Identity sources"" {
  class HR_System {
    +EmployeeID
    +Department
    +ManagerID
    +Location
  }

  class AD_User {
    +sAMAccountName
    +userPrincipalName
    +extensionAttribute1  // OrgPath (canonical)
    +extensionAttribute2  // OrgPath depth
  }

  class AD_Computer {
    +dNSHostName
    +extensionAttribute1  // OrgPath (canonical)
  }
}

package ""OrgPath pipeline"" {
  class OrgPath_Resolver {
    +Resolve(userOrDevice) : OrgPath
    +Validate(path) : bool
  }

  class OrgPath_Rules {
    +HR_to_OrgPath()
    +AD_Fallback()
  }
}

package ""Consumers"" {
  class Dynamic_Groups
  class Conditional_Access
  class Admin_Units
  class Intune_Scopes
}

HR_System --> OrgPath_Resolver : HR attributes
AD_User --> OrgPath_Resolver : extensionAttribute1/2
AD_Computer --> OrgPath_Resolver : extensionAttribute1

OrgPath_Resolver --> OrgPath_Rules
OrgPath_Resolver --> Dynamic_Groups
OrgPath_Resolver --> Conditional_Access
OrgPath_Resolver --> Admin_Units
OrgPath_Resolver --> Intune_Scopes

@enduml
"@

$diagram1Target = Join-Path $RepoRoot "src\uiao\canon\diagrams\orgpath-logical-model.puml"
[IO.Directory]::CreateDirectory((Split-Path $diagram1Target -Parent)) | Out-Null
[IO.File]::WriteAllText($diagram1Target, $orgPathDiagram1, [Text.Encoding]::UTF8)
Write-Host "Writing OrgPath logical model diagram..."
Write-Host "  OK  $diagram1Target" -ForegroundColor Green

# --- Architecture diagram 2 ? OrgPath data flow (PlantUML) ---
$orgPathDiagram2 = @"
@startuml
title OrgPath data flow (UIAO)

skinparam backgroundColor #FFFFFF
skinparam defaultTextAlignment left

actor HR as ""HR System""
actor AD as ""Active Directory""
actor Entra as ""Entra ID""
actor Admin as ""Admin / Operator""

rectangle ""HR / Source systems"" {
  HR --> (HR Export)
}

rectangle ""Identity platform"" {
  (HR Export) --> AD : HR-driven join\n(EmployeeID, Manager, Dept)
  AD --> (OrgPath Stamping Script) : extensionAttribute1/2
  (OrgPath Stamping Script) --> Entra : sync via AAD Connect
}

rectangle ""Policy & governance"" {
  Entra --> (Dynamic Groups)
  Entra --> (Conditional Access)
  Entra --> (Admin Units)
  Entra --> (Intune Scopes)
}

Admin --> (OrgPath Stamping Script) : configure rules\nand mappings
Admin --> Entra : validate groups\nand policy targeting

@enduml
"@

$diagram2Target = Join-Path $RepoRoot "src\uiao\canon\diagrams\orgpath-data-flow.puml"
[IO.Directory]::CreateDirectory((Split-Path $diagram2Target -Parent)) | Out-Null
[IO.File]::WriteAllText($diagram2Target, $orgPathDiagram2, [Text.Encoding]::UTF8)
Write-Host "Writing OrgPath data flow diagram..."
Write-Host "  OK  $diagram2Target" -ForegroundColor Green

